---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

interface Props extends HTMLAttributes<"div"> {
  multiple?: boolean
  defaultValue?: string | string[]
  disabled?: boolean
  orientation?: "horizontal" | "vertical"
  loopFocus?: boolean
  hiddenUntilFound?: boolean
  collapsible?: boolean
}

const {
  class: className,
  multiple,
  defaultValue,
  disabled,
  orientation = "vertical",
  loopFocus,
  hiddenUntilFound,
  collapsible,
  ...props
} = Astro.props

const booleanDataAttr = (value?: boolean) =>
  value === undefined ? undefined : value ? "" : "false"

const serializedDefaultValue = Array.isArray(defaultValue)
  ? JSON.stringify(defaultValue)
  : defaultValue
---

<div
  data-slot="accordion"
  data-multiple={booleanDataAttr(multiple)}
  data-default-value={serializedDefaultValue}
  data-disabled={booleanDataAttr(disabled)}
  data-orientation={orientation}
  data-loop-focus={booleanDataAttr(loopFocus)}
  data-hidden-until-found={booleanDataAttr(hiddenUntilFound)}
  data-collapsible={booleanDataAttr(collapsible)}
  class={cn("flex w-full flex-col", className)}
  {...props}
>
  <slot />
</div>

<script>
  import { create } from "@data-slot/accordion"

  create()
</script>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

interface Props extends HTMLAttributes<"div"> {
  value: string
  disabled?: boolean
}

const { class: className, value, disabled, ...props } = Astro.props
---

<div
  data-slot="accordion-item"
  data-value={value}
  data-disabled={disabled ? "" : undefined}
  class={cn("group/accordion-item not-last:border-b", className)}
  {...props}
>
  <slot />
</div>
